import { useState, useEffect } from "react";
import { useSelector, useDispatch } from "react-redux";
import { toast } from "react-toastify";
import bcrypt from "bcryptjs";
import { login } from "../authReducer";

function Dashboard() {
  const user = useSelector((state) => state.auth.user);
  const dispatch = useDispatch();
  const [name, setName] = useState(user?.name || "");
  const [email, setEmail] = useState(user?.email || "");
  const [password, setPassword] = useState("");
  const [classId, setClassId] = useState(user?.classId || "");
  const [avatarFile, setAvatarFile] = useState(null);
  const [classes, setClasses] = useState([]);
  const [notifications, setNotifications] = useState([]);

  useEffect(() => {
    if (user?.role === "student") {
      fetch("http://localhost:3001/classes")
        .then((res) => res.json())
        .then((data) => setClasses(data))
        .catch((error) => toast.error("Ошибка загрузки классов"));
    }
    fetch(`http://localhost:3001/notifications?userId=${user.id}`)
      .then((res) => res.json())
      .then((data) => setNotifications(data.sort((a, b) => new Date(b.createdAt) - new Date(a.createdAt))))
      .catch((error) => toast.error("Ошибка загрузки уведомлений"));
  }, [user]);

  async function handleSubmit(e) {
    e.preventDefault();
    try {
      let avatarPath = user.avatar;
      if (avatarFile) {
        const allowedTypes = ["image/jpeg", "image/png"];
        const maxSize = 2 * 1024 * 1024;
        if (!allowedTypes.includes(avatarFile.type)) {
          toast.error("Допустимы только изображения (JPEG, PNG)");
          return;
        }
        if (avatarFile.size > maxSize) {
          toast.error("Файл слишком большой. Максимальный размер: 2 МБ");
          return;
        }
        const formData = new FormData();
        formData.append("file", avatarFile);
        const uploadResponse = await fetch("http://localhost:3002/upload", {
          method: "POST",
          body: formData,
        });
        const uploadData = await uploadResponse.json();
        if (uploadResponse.ok) {
          avatarPath = uploadData.filePath;
        } else {
          toast.error("Не удалось загрузить аватар");
          return;
        }
      }

      const emailResponse = await fetch(`http://localhost:3001/users?email=${email}&id_ne=${user.id}`);
      const existingUsers = await emailResponse.json();
      if (existingUsers.length > 0) {
        toast.error("Этот email уже используется");
        return;
      }

      const updatedUser = {
        name,
        email,
        role: user.role,
        classId: user.role === "student" ? parseInt(classId) || null : null,
        avatar: avatarPath,
        isBanned: user.isBanned,
      };
      if (password) {
        updatedUser.password = await bcrypt.hash(password, 10);
      } else {
        updatedUser.password = user.password;
      }

      const response = await fetch(`http://localhost:3001/users/${user.id}`, {
        method: "PATCH",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(updatedUser),
      });

      if (response.ok) {
        const updatedUserData = await response.json();
        dispatch(login(updatedUserData));
        toast.success("Данные успешно обновлены!");
      } else {
        toast.error("Не удалось обновить данные");
      }
    } catch (error) {
      toast.error("Сетевая ошибка при обновлении данных");
    }
  }

  async function handleDeleteNotification(id) {
    try {
      const response = await fetch(`http://localhost:3001/notifications/${id}`, {
        method: "DELETE",
      });
      if (response.ok) {
        setNotifications(notifications.filter((n) => n.id !== id));
        toast.success("Уведомление удалено!");
      } else {
        toast.error("Не удалось удалить уведомление");
      }
    } catch (error) {
      toast.error("Сетевая ошибка при удалении уведомления");
    }
  }

  if (!user) {
    return <div className="container mt-5"><h1>Пожалуйста, войдите в систему</h1></div>;
  }

  return (
    <div className="container mt-5">
      <h1 className="text-center mb-4">Личный кабинет</h1>
      <div className="row">
        <div className="col-md-6">
          <div className="card shadow mb-4">
            <div className="card-body">
              <h2 className="card-title">Редактировать профиль</h2>
              <form onSubmit={handleSubmit}>
                <div className="mb-3">
                  <label htmlFor="name" className="form-label">Имя</label>
                  <input
                    type="text"
                    id="name"
                    className="form-control"
                    value={name}
                    onChange={(e) => setName(e.target.value)}
                    required
                  />
                </div>
                <div className="mb-3">
                  <label htmlFor="email" className="form-label">Email</label>
                  <input
                    type="email"
                    id="email"
                    className="form-control"
                    value={email}
                    onChange={(e) => setEmail(e.target.value)}
                    required
                  />
                </div>
                <div className="mb-3">
                  <label htmlFor="password" className="form-label">Новый пароль (опционально)</label>
                  <input
                    type="password"
                    id="password"
                    className="form-control"
                    value={password}
                    onChange={(e) => setPassword(e.target.value)}
                    placeholder="Оставьте пустым, чтобы не менять"
                  />
                </div>
                {user.role === "student" && (
                  <div className="mb-3">
                    <label htmlFor="classId" className="form-label">Класс</label>
                    <select
                      id="classId"
                      className="form-select"
                      value={classId}
                      onChange={(e) => setClassId(e.target.value)}
                      required
                    >
                      <option value="">-- Выберите класс --</option>
                      {classes.map((cls) => (
                        <option key={cls.id} value={cls.id}>
                          {cls.name}
                        </option>
                      ))}
                    </select>
                  </div>
                )}
                <div className="mb-3">
                  <label htmlFor="avatar" className="form-label">Аватар (опционально, JPEG/PNG, до 2 МБ)</label>
                  <input
                    type="file"
                    id="avatar"
                    className="form-control"
                    onChange={(e) => setAvatarFile(e.target.files[0])}
                  />
                  {user.avatar && (
                    <div className="mt-2">
                      <img src={`http://localhost:3002${user.avatar}`} alt="Аватар" className="img-thumbnail" style={{ maxWidth: "100px" }} />
                    </div>
                  )}
                </div>
                <button type="submit" className="btn btn-primary w-100">Сохранить изменения</button>
              </form>
            </div>
          </div>
        </div>
        <div className="col-md-6">
          <div className="card shadow">
            <div className="card-body">
              <h2 className="card-title">Уведомления</h2>
              {notifications.length === 0 ? (
                <p>Уведомлений нет</p>
              ) : (
                <ul className="list-group">
                  {notifications.map((notification) => (
                    <li key={notification.id} className="list-group-item d-flex justify-content-between align-items-center">
                      <div>
                        <small>{new Date(notification.createdAt).toLocaleString()}</small>
                        <p>{notification.message}</p>
                      </div>
                      <button
                        className="btn btn-danger btn-sm"
                        onClick={() => handleDeleteNotification(notification.id)}
                      >
                        Удалить
                      </button>
                    </li>
                  ))}
                </ul>
              )}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

export default Dashboard;
